// WebGPU compat test #12 — aether's Q4_K dequant-matvec WGSL kernel under monster.
//
// WGSL_MATVEC_Q4_K (+ its scale_min_k4 helper and f16_to_f32) copied VERBATIM
// from open-source/aether/dist-browser/sovereign-shaders.js. Q4_K super-block =
// 256 elems / 144 bytes: f16 d, f16 dmin, 12B packed 6-bit scales+mins (the
// llama.cpp get_scale_min_k4 layout), 128B of 4-bit quants. One block per row.
// value = d·sc·(q&0xf) − dmin·m. Golden-diffed monster vs the Deno
// real-navigator.gpu oracle.
//
// The CPU reference mirrors the WGSL scale_min_k4 + decode BIT-FOR-BIT (not the
// vickrey 'linear' Q4_K decoder, which packs the 12 scale bytes differently), so
// agreement proves the SHADER, decoupled from any host-side packer. Scales `d`
// and `dmin` are half-exact; quants are nibbles → dequant is exact (1e-4 band
// only absorbs GPU accumulation order).
//
// Inline pure-JS encoders; single-declarator consts only (monster gap).

function f32bytes(x) {
  if (x === 0) return [0, 0, 0, 0];
  const sign = x < 0 ? 1 : 0; x = Math.abs(x);
  let e = Math.floor(Math.log2(x)); let m = x / Math.pow(2, e);
  if (m < 1) { m *= 2; e -= 1; } if (m >= 2) { m /= 2; e += 1; }
  const bits = ((sign << 31) | ((e + 127) << 23) | Math.round((m - 1) * Math.pow(2, 23))) >>> 0;
  return [bits & 0xff, (bits >>> 8) & 0xff, (bits >>> 16) & 0xff, (bits >>> 24) & 0xff];
}
function f16bytes(x) {
  if (x === 0) return [0, 0];
  const sign = x < 0 ? 1 : 0; x = Math.abs(x);
  let e = Math.floor(Math.log2(x)); let m = x / Math.pow(2, e);
  if (m < 1) { m *= 2; e -= 1; } if (m >= 2) { m /= 2; e += 1; }
  const bits = ((sign << 15) | ((e + 15) << 10) | (Math.round((m - 1) * Math.pow(2, 10)) & 0x3ff)) & 0xffff;
  return [bits & 0xff, (bits >>> 8) & 0xff];
}
function bytesToF32(b0, b1, b2, b3) {
  const bits = ((b0) | (b1 << 8) | (b2 << 16) | (b3 << 24)) >>> 0;
  const sign = (bits >>> 31) & 1 ? -1 : 1;
  const exp = (bits >>> 23) & 0xff;
  const mant = bits & 0x7fffff;
  if (exp === 0) return sign * mant * Math.pow(2, -149);
  if (exp === 255) return mant ? NaN : sign * Infinity;
  return sign * (1 + mant / Math.pow(2, 23)) * Math.pow(2, exp - 127);
}
function u32bytes(v) { return [v & 0xff, (v >>> 8) & 0xff, (v >>> 16) & 0xff, (v >>> 24) & 0xff]; }
function q4(v) { const s = v < 0 ? -1 : 1; return s * Math.round(Math.abs(v) * 1e4) / 1e4; }

const out = {};
const adapter = await navigator.gpu.requestAdapter();
const device = await adapter.requestDevice();

const ROWS = 2;
const COLS = 256;            // exactly one Q4_K super-block per row
const BLOCKS_PER_ROW = 1;
const BLOCK_BYTES = 144;
// 144 is a multiple of 4 → no row padding needed; wordsPerRow unused by Q4_K
// (it strides on blocksPerRow*144), but Dims still carries it.
const WORDS_PER_ROW = BLOCK_BYTES / 4; // 36

// Per-row d / dmin (half-exact).
function dVal(row) { return row === 0 ? 0.5 : 0.25; }
function dminVal(row) { return row === 0 ? 0.125 : 0.0625; }
// 6-bit sub-block scales (0..63) and mins (0..63), 8 each, per row.
function scVal(row, j) { return ((j + row) % 13) + 1; }     // 1..13
function mnVal(row, j) { return ((j * 2 + row) % 11) + 1; } // 1..11
// 4-bit quants (0..15), 256 per row.
function qVal(row, i) { return (i + row * 3) % 16; }
// Activation x[col] (exact small f32).
function xVal(c) { return ((c % 5) - 2) * 0.25; } // -0.5..0.5

// ── Pack the 12 scale bytes the llama.cpp get_scale_min_k4 way ───────────────
// Inverse of scale_min_k4: for j in 0..3, scale low6 in byte[j] bits0-5, min low6
// in byte[j+4] bits0-5. For j in 4..7, scale = (byte[j+4]&0xF) | ((byte[j-4]>>6)<<4),
// min = (byte[j+4]>>4) | ((byte[j]>>6)<<4). We assemble bytes 0..11 so that the
// decode returns scVal/mnVal exactly.
function packScaleBytes(row) {
  const sb = [];
  for (let i = 0; i < 12; i++) sb.push(0);
  // j 0..3: byte[j] bits0-5 = sc, byte[j+4] bits0-5 = mn
  for (let j = 0; j < 4; j++) {
    sb[j] = (sb[j] & 0xc0) | (scVal(row, j) & 0x3f);
    sb[j + 4] = (sb[j + 4] & 0xc0) | (mnVal(row, j) & 0x3f);
  }
  // j 4..7:
  //   sc = (byte[j+4] & 0xF) | ((byte[j-4] >> 6) << 4)   → low nibble in byte[j+4],
  //        high 2 bits go to byte[j-4] bits 6-7
  //   mn = (byte[j+4] >> 4) | ((byte[j] >> 6) << 4)       → high nibble in byte[j+4],
  //        high 2 bits go to byte[j] bits 6-7
  for (let j = 4; j < 8; j++) {
    const scv = scVal(row, j) & 0x3f;
    const mnv = mnVal(row, j) & 0x3f;
    const scLow4 = scv & 0xf;
    const scHi2 = (scv >> 4) & 0x3;
    const mnHi4 = mnv & 0xf;
    const mnHi2 = (mnv >> 4) & 0x3;
    // byte[j+4] = scLow4 (low nibble) | (mnHi4 << 4) (high nibble)
    sb[j + 4] = (scLow4 & 0xf) | ((mnHi4 & 0xf) << 4);
    // byte[j-4] bits 6-7 = scHi2 ; byte[j] bits 6-7 = mnHi2
    sb[j - 4] = (sb[j - 4] & 0x3f) | (scHi2 << 6);
    sb[j] = (sb[j] & 0x3f) | (mnHi2 << 6);
  }
  return sb;
}

// JS mirror of WGSL scale_min_k4 (returns [scale, min]).
function scaleMinK4(sb, j) {
  if (j < 4) return [sb[j] & 63, sb[j + 4] & 63];
  const sc = (sb[j + 4] & 0xf) | (((sb[j - 4] >> 6) & 0x3) << 4);
  const m = (sb[j + 4] >> 4) | (((sb[j] >> 6) & 0x3) << 4);
  return [sc, m];
}

// Build the weight buffer (ROWS x 144 bytes).
let wBytes = [];
for (let row = 0; row < ROWS; row++) {
  let rb = [];
  rb = rb.concat(f16bytes(dVal(row)));      // 2
  rb = rb.concat(f16bytes(dminVal(row)));   // 2
  rb = rb.concat(packScaleBytes(row));      // 12
  // 128 bytes of 4-bit quants: byte holds (low nibble = elem 2k, high = elem 2k+1)
  for (let p = 0; p < 128; p++) {
    const lo = qVal(row, 2 * p) & 0xf;
    const hi = qVal(row, 2 * p + 1) & 0xf;
    rb = rb.concat([(lo | (hi << 4)) & 0xff]);
  }
  wBytes = wBytes.concat(rb);
}
const W_BYTES_TOTAL = ROWS * BLOCK_BYTES;

let xBytes = [];
for (let c = 0; c < COLS; c++) xBytes = xBytes.concat(f32bytes(xVal(c)));
const X_BYTES_TOTAL = COLS * 4;

let dimBytes = [];
dimBytes = dimBytes.concat(u32bytes(ROWS)).concat(u32bytes(COLS))
  .concat(u32bytes(BLOCKS_PER_ROW)).concat(u32bytes(WORDS_PER_ROW)).concat(u32bytes(ROWS));
const DIM_BYTES_TOTAL = 5 * 4;
const Y_BYTES_TOTAL = ROWS * 4;

const wBuf = device.createBuffer({ size: W_BYTES_TOTAL, usage: GPUBufferUsage.STORAGE | GPUBufferUsage.COPY_DST });
device.queue.writeBuffer(wBuf, 0, new Uint8Array(wBytes));
const xBuf = device.createBuffer({ size: X_BYTES_TOTAL, usage: GPUBufferUsage.STORAGE | GPUBufferUsage.COPY_DST });
device.queue.writeBuffer(xBuf, 0, new Uint8Array(xBytes));
const yBuf = device.createBuffer({ size: Y_BYTES_TOTAL, usage: GPUBufferUsage.STORAGE | GPUBufferUsage.COPY_SRC });
const dBuf = device.createBuffer({ size: DIM_BYTES_TOTAL, usage: GPUBufferUsage.UNIFORM | GPUBufferUsage.COPY_DST });
device.queue.writeBuffer(dBuf, 0, new Uint8Array(dimBytes));

const shader = device.createShaderModule({
  code: `
fn f16_to_f32(h: u32) -> f32 {
  let sign = (h >> 15u) & 1u;
  let exp  = (h >> 10u) & 0x1Fu;
  let frac = h & 0x3FFu;
  var val: f32;
  if (exp == 0u) {
    val = (f32(frac) / 1024.0) * 0.00006103515625;
  } else if (exp == 0x1Fu) {
    val = select(3.0e38, 0.0, frac != 0u);
  } else {
    val = (1.0 + f32(frac) / 1024.0) * exp2(f32(i32(exp) - 15));
  }
  return select(val, -val, sign == 1u);
}
struct Dims { rows: u32, cols: u32, blocksPerRow: u32, wordsPerRow: u32, dispatchRowsX: u32 };
@group(0) @binding(0) var<storage, read> w: array<u32>;
@group(0) @binding(1) var<storage, read> x: array<f32>;
@group(0) @binding(2) var<storage, read_write> y: array<f32>;
@group(0) @binding(3) var<uniform> d: Dims;

fn wbyte(off: u32) -> u32 {
  let word = w[off >> 2u];
  let shift = (off & 3u) * 8u;
  return (word >> shift) & 0xFFu;
}
fn scale_min_k4(scalesBase: u32, j: u32) -> vec2<f32> {
  if (j < 4u) {
    return vec2<f32>(f32(wbyte(scalesBase + j) & 63u), f32(wbyte(scalesBase + j + 4u) & 63u));
  }
  let sc = (wbyte(scalesBase + j + 4u) & 0xFu) | ((wbyte(scalesBase + j - 4u) >> 6u) << 4u);
  let m  = (wbyte(scalesBase + j + 4u) >> 4u) | ((wbyte(scalesBase + j) >> 6u) << 4u);
  return vec2<f32>(f32(sc), f32(m));
}
var<workgroup> partial: array<f32, 64>;
@compute @workgroup_size(64, 1, 1)
fn main(@builtin(workgroup_id) wid: vec3<u32>, @builtin(local_invocation_id) lid: vec3<u32>) {
  let row = wid.x + wid.y * d.dispatchRowsX;
  let tid = lid.x;
  if (row >= d.rows) { return; }
  let rowByteBase = row * d.blocksPerRow * 144u;
  var acc: f32 = 0.0;
  var b: u32 = tid;
  loop {
    if (b >= d.blocksPerRow) { break; }
    let blockBase = rowByteBase + b * 144u;
    let dv   = f16_to_f32(wbyte(blockBase) | (wbyte(blockBase + 1u) << 8u));
    let dmin = f16_to_f32(wbyte(blockBase + 2u) | (wbyte(blockBase + 3u) << 8u));
    let scalesBase = blockBase + 4u;
    let qsBase = blockBase + 16u;
    let colBase = b * 256u;
    for (var g: u32 = 0u; g < 4u; g = g + 1u) {
      let j = g * 64u;
      let sm1 = scale_min_k4(scalesBase, j >> 5u);
      let sm2 = scale_min_k4(scalesBase, (j >> 5u) + 1u);
      let qb = (j >> 6u) * 32u;
      for (var l: u32 = 0u; l < 32u; l = l + 1u) {
        let qbyte = wbyte(qsBase + qb + l);
        let v0 = dv * sm1.x * f32(qbyte & 0xFu) - dmin * sm1.y;
        let v1 = dv * sm2.x * f32(qbyte >> 4u) - dmin * sm2.y;
        acc = acc + v0 * x[colBase + j + l];
        acc = acc + v1 * x[colBase + j + 32u + l];
      }
    }
    b = b + 64u;
  }
  partial[tid] = acc;
  workgroupBarrier();
  var stride: u32 = 32u;
  loop {
    if (stride == 0u) { break; }
    if (tid < stride) { partial[tid] = partial[tid] + partial[tid + stride]; }
    workgroupBarrier();
    stride = stride >> 1u;
  }
  if (tid == 0u) { y[row] = partial[0]; }
}
`,
});
const pipeline = device.createComputePipeline({ layout: 'auto', compute: { module: shader, entryPoint: 'main' } });
const bindGroup = device.createBindGroup({
  layout: pipeline.getBindGroupLayout(0),
  entries: [
    { binding: 0, resource: { buffer: wBuf } },
    { binding: 1, resource: { buffer: xBuf } },
    { binding: 2, resource: { buffer: yBuf } },
    { binding: 3, resource: { buffer: dBuf } },
  ],
});
const enc = device.createCommandEncoder();
const pass = enc.beginComputePass();
pass.setPipeline(pipeline);
pass.setBindGroup(0, bindGroup);
pass.dispatchWorkgroups(ROWS, 1, 1);
pass.end();
const readBuf = device.createBuffer({ size: Y_BYTES_TOTAL, usage: GPUBufferUsage.COPY_DST | GPUBufferUsage.MAP_READ });
enc.copyBufferToBuffer(yBuf, 0, readBuf, 0, Y_BYTES_TOTAL);
device.queue.submit([enc.finish()]);

await readBuf.mapAsync(GPUMapMode.READ);
const px = new Uint8Array(readBuf.getMappedRange());
let gpu = [];
for (let r = 0; r < ROWS; r++) { const o = r * 4; gpu = gpu.concat([bytesToF32(px[o], px[o + 1], px[o + 2], px[o + 3])]); }
readBuf.unmap();

// CPU reference mirroring the WGSL decode loop EXACTLY — including reading the
// quant nibbles from the SAME packed byte the shader reads (qsBase + g*32 + l):
// low nibble → element j+l, high nibble → element j+32+l. (The packing assigns
// nibbles by byte order; the decode reads by that same byte order, so we must
// read the packed buffer, not re-derive from qVal's element index.)
function wbyteJS(off) { return wBytes[off] & 0xff; }
let cpu = [];
for (let row = 0; row < ROWS; row++) {
  const sb = packScaleBytes(row);
  const dv = dVal(row);
  const dmin = dminVal(row);
  const rowBase = row * BLOCK_BYTES;
  const qsBase = rowBase + 16;
  let acc = 0;
  for (let g = 0; g < 4; g++) {
    const j = g * 64;
    const sm1 = scaleMinK4(sb, j >> 5);
    const sm2 = scaleMinK4(sb, (j >> 5) + 1);
    const qb = (j >> 6) * 32;
    for (let l = 0; l < 32; l++) {
      const qbyte = wbyteJS(qsBase + qb + l);
      const qLo = qbyte & 0xf;
      const qHi = (qbyte >> 4) & 0xf;
      const v0 = dv * sm1[0] * qLo - dmin * sm1[1];
      const v1 = dv * sm2[0] * qHi - dmin * sm2[1];
      acc += v0 * xVal(j + l);
      acc += v1 * xVal(j + 32 + l);
    }
  }
  cpu = cpu.concat([acc]);
}

out.gpu = gpu.map(q4);
out.cpu = cpu.map(q4);
console.error('RAW gpu=' + JSON.stringify(gpu) + ' cpu=' + JSON.stringify(cpu));
console.log('__RESULT__ ' + JSON.stringify(out));
